package ua.university.sms.service;import org.springframework.stereotype.Service;import ua.university.sms.exception.NotFoundException;import ua.university.sms.model.dto.StudentDtos.*;import ua.university.sms.model.entity.*;import ua.university.sms.repository.*;import java.util.*;
@Service public class StudentService{private final StudentRepository repo;private final EnrollmentRepository enr;public StudentService(StudentRepository r,EnrollmentRepository e){repo=r;enr=e;}public Response create(Request d){Student s=new Student();apply(s,d);return toDto(repo.save(s));}public Response get(Long id){return toDto(find(id));}public List<Response> list(StudentStatus status,Integer year,String search){List<Student> data=search!=null&&!search.isBlank()?repo.findByFullNameContainingIgnoreCaseOrEmailContainingIgnoreCase(search,search):status!=null?repo.findByStatus(status):year!=null?repo.findByYear(year):repo.findAll();return data.stream().map(this::toDto).toList();}public Response update(Long id,Request d){Student s=find(id);apply(s,d);return toDto(repo.save(s));}public void delete(Long id){repo.delete(find(id));}public List<Response> unpaid(){return repo.findStudentsWithUnpaidCourses().stream().map(this::toDto).toList();}public List<Response> top(int n){return repo.findAll().stream().map(this::toDto).sorted(Comparator.comparing(Response::gpa,Comparator.nullsLast(Comparator.reverseOrder()))).limit(n).toList();}Student find(Long id){return repo.findById(id).orElseThrow(()->new NotFoundException("Student not found: "+id));}Double gpa(Long id){var grades=enr.findByStudentId(id).stream().map(Enrollment::getGrade).filter(Objects::nonNull).toList();return grades.isEmpty()?null:grades.stream().mapToDouble(Double::doubleValue).average().orElse(0);}private void apply(Student s,Request d){s.setFullName(d.fullName());s.setEmail(d.email());s.setYear(d.year());s.setStatus(d.status()==null?StudentStatus.ACTIVE:d.status());}private Response toDto(Student s){return new Response(s.getId(),s.getFullName(),s.getEmail(),s.getYear(),s.getStatus(),gpa(s.getId()));}}
